long long exGCD(long long a, long long b, long long& x, long long& y) {

	if (b == 0) {

		x = 1;

		y = 0;

		return a;

	}

	long long g = exGCD(b, a % b, x, y);

	long long temp = x;

	x = y;

	y = temp - a / b * y;

	return g;

}

int inverse(long long a) {

	long long x, y;

	exGCD(a, MOD, x, y);

	return (x % MOD + MOD) % MOD;

